	@Test
	void laterAdditionInvalidatesColdSynopsisWithoutForcingAnotherRebuild(@TempDir File dataDir) throws Exception {
		LmdbStore store = initializedStore(dataDir, coldSnapshotOnlyConfig(256));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			loadRows(repository, 64);
			rebuildAndPersist(store);
			assertEquals(EvaluationStatistics.FilterPassEstimate.Source.EXACT, estimate(store, QUERY).getSource());

			try (var connection = repository.getConnection()) {
				ValueFactory vf = repository.getValueFactory();
				connection.add(vf.createIRI("urn:test:later"), vf.createIRI("urn:test:cold-value"),
						vf.createLiteral("keep"));
			}
			assertTrue(store.getBackingStore().getSketchBasedJoinEstimator().persistIfDirty());

			assertNotEquals(EvaluationStatistics.FilterPassEstimate.Source.EXACT, estimate(store, QUERY).getSource());
			assertFalse(Files.exists(dataDir.toPath().resolve(COLD_SYNOPSIS_FILE)));
		} finally {
			repository.shutDown();
		}
	}

